/* Return the largest sum of any contiguous subarray in the vector x.
   This implementation uses the classic Kadane algorithm for O(n) time
   complexity while preserving the exact output semantics of the
   original nested-loop solution. */
int maximumSubarray(std::vector<int> const& x) {
    // Handle empty input defensively (though not required by spec)
    if (x.empty()) return 0;

    int current_sum = 0;
    int max_sum = std::numeric_limits<int>::lowest();

    for (auto val : x) {
        current_sum = std::max(val, current_sum + val);
        if (current_sum > max_sum) max_sum = current_sum;
    }
    return max_sum;
}
