    #pragma omp parallel for schedule(static)
    for (intptr_t i = 0; i < static_cast<intptr_t>(y.size()); ++i) {
        y[i] *= beta;
    }

    /* 2) Accumulate the sparse matrix contribution.
       We keep the original bounds checking logic; the check per element
       is inexpensive compared to the data‑movement cost. */
    #pragma omp parallel for schedule(static)
    for (intptr_t i = 0; i < static_cast<intptr_t>(A.size()); ++i) {
        auto const& a = A[i];
        if (a.row < y.size() && a.column < x.size()) {
            y[a.row] += alpha * a.value * x[a.column];
