#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <omp.h>

#if !defined(M_PI)
constexpr double M_PI = 3.14159265358979323846;
#endif

// Compute the discrete Fourier transform of x.
// The result is written into output, whose size will be set to N.
inline void dft(const std::vector<double>& x, std::vector<std::complex<double>>& output)
{
    const int N = static_cast<int>(x.size());
    output.assign(N, std::complex<double>(0.0, 0.0));

    // Parallelise over the output index k.
    #pragma omp parallel for schedule(static)
    for (int k = 0; k < N; ++k) {
        std::complex<double> sum(0.0, 0.0);

        // Incrementally compute the angle to avoid repeated division.
        const double two_pi_k_over_N = 2.0 * M_PI * static_cast<double>(k) / static_cast<double>(N);
        double angle = 0.0;

        for (int n = 0; n < N; ++n) {
            // Build the complex exponential from sin/cos
            double c, s;
            std::sincos(angle, &s, &c);               // s = sin(angle), c = cos(angle)
            sum += std::complex<double>(c, -s) * x[n];

            angle += two_pi_k_over_N;                 // Increment angle for next n
        }
        output[k] = sum;
    }
}
