#include <array>
#include <cstddef>
#include <omp.h>

/* Count the number of pixels in image with each grayscale intensity.
   The vector `image` is a grayscale image with values 0-255.
   Store the results in `bins`.
   Example:
   input: image=[2, 116, 201, 11, 92, 92, 201, 4, 2]
   output: [0, 0, 2, 0, 1, ...]
   The implementation uses OpenMP to reduce work across threads and avoid
   atomic updates on the shared array. */
void pixelCounts(std::vector<int> const& image, std::array<size_t, 256> &bins) {
    // Reset output bins to zero
    bins.fill(0);

    // Determine number of threads (if OMP not active, nthreads == 1)
    int nthreads = omp_get_max_threads();

    // Allocate per‑thread local bins
    std::vector<std::array<size_t, 256>> local(nthreads);
    for (auto &a : local) a.fill(0);

    // Parallel loop using static schedule; each thread updates its own local array
    #pragma omp parallel
    {
        int tid = omp_get_thread_num();
        auto &local_bins = local[tid];

        #pragma omp for
        for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(image.size()); ++i) {
            ++local_bins[static_cast<unsigned char>(image[i])];
        }
    }

    // Merge local results into final output
    for (int t = 0; t < nthreads; ++t) {
        for (int v = 0; v < 256; ++v) {
            bins[v] += local[t][v];
        }
    }
}
