18_graph_count_components:
```cpp
#pragma once
#include <vector>
#include <stack>
#include <cstddef>

/* Count the number of connected components in the undirected graph
   defined by the adjacency matrix `A`.  The matrix is stored in
   row-major order and contains only 0/1 values.  The algorithm is
   fully deterministic and keeps the same semantics as the original
   recursive DFS implementation.  It is intentionally written to be
   cache friendly, use a small stack and avoid expensive function
   calls. */
inline int componentCount(std::vector<int> const& A, std::size_t N)
{
    // Fast path for an empty graph.
    if (N == 0) return 0;

    // Use a byte per node for visited flags – far less expensive than
    // std::vector<bool> which uses bit packing.
    std::vector<char> visited(N, 0);
    int components = 0;

    // Manual stack for DFS (depth first search).
    std::vector<int> stack;
    stack.reserve(N);          // avoid reallocations

    for (std::size_t start = 0; start < N; ++start)
    {
        if (visited[start]) continue;

        // Start a new component.
        ++components;
        visited[start] = 1;
        stack.clear();
        stack.push_back(static_cast<int>(start));

        while (!stack.empty())
        {
            int node = stack.back();
            stack.pop_back();

            // Iterate over the row of the adjacency matrix.
            int const* row = A.data() + node * static_cast<int>(N);
            for (int i = 0; i < static_cast<int>(N); ++i)
            {
                if (row[i] && !visited[i])
                {
                    visited[i] = 1;
                    stack.push_back(i);
                }
            }
        }
    }
    return components;
}
