#pragma once
#include <vector>
#include <cstddef>
#include <limits>
#include <cstring>

/*
 * Returns the length of the shortest path between `source` and `dest`
 * in an undirected graph represented by a row-major NxN adjacency matrix
 * `A`.  The graph is assumed to be connected.
 *
 * The implementation uses a level‑by‑level BFS with two simple int
 * vectors as queues.  Visited nodes are stored in a byte array to
 * improve cache locality.  No parallelism is used because BFS on a
 * single graph is inherently sequential in this context.
 */
inline int shortestPathLength(std::vector<int> const& A,
                              std::size_t N,
                              int source, int dest) {
    // Visited array: 0 = unvisited, 1 = visited
    std::vector<unsigned char> visited(N, 0);
    std::vector<int> frontier;          // current level
    std::vector<int> nextFrontier;      // next level
    frontier.reserve(N);
    nextFrontier.reserve(N);

    visited[source] = 1;
    frontier.push_back(source);
    int distance = 0;

    while (!frontier.empty()) {
        nextFrontier.clear();
        for (int cur : frontier) {
            if (cur == dest) return distance;
            // iterate over all possible neighbors
            size_t row = static_cast<size_t>(cur) * N;
            for (size_t j = 0; j < N; ++j) {
                if (A[row + j] && !visited[j]) {
                    visited[j] = 1;
                    nextFrontier.push_back(static_cast<int>(j));
                }
            }
        }
        frontier.swap(nextFrontier);
        ++distance;
    }

    return std::numeric_limits<int>::max();
}
