 * semantics of the original single‑pass implementation: every element
 * of x is multiplied by alpha, and the elements of y are added as is.
 *
 * Parallelization strategy:
 *   - The contribution of x and y to z are independent of each other.
 *   - We therefore accumulate the effects of x and of y in two separate
 *     parallel loops, each using an atomic update to protect concurrent
 *     writes to z.
 */
void sparseAxpy(double alpha,
                std::vector<Element> const& x,
                std::vector<Element> const& y,
                std::vector<double> &z)
{
