#pragma once
#include <vector>
#include <unordered_map>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* LU factorization of a sparse NxN matrix A (COO).
 * The result is written into the flat row‑major arrays L and U.
 * The algorithm is identical to the textbook LU decomposition
 * with no pivoting.  The code is fully parallelised over the
 * outermost loop (rows).
 */
inline void luFactorize(const std::vector<COOElement>& A,
                        std::vector<double>& L,
                        std::vector<double>& U,
                        size_t N)
{
    /* ------------------------------------------------------------------
     *  1. Build a dense representation of the input matrix.
     *     We use a single flat vector to avoid the costly
     *     std::vector<std::vector<double>> indirection.
     * ------------------------------------------------------------------ */
    std::vector<double> A_dense(static_cast<size_t>(N) * N, 0.0);
    for (const auto& e : A) {
        A_dense[e.row * N + e.column] = e.value;
    }

    /* ------------------------------------------------------------------
     *  2. Initialise L and U to zero.
     * ------------------------------------------------------------------ */
    L.assign(N * N, 0.0);
    U.assign(N * N, 0.0);

    /* ------------------------------------------------------------------
     *  3. LU decomposition.
     *     The outer loop over rows is independent of each other
     *     and is therefore fully parallelisable.
     * ------------------------------------------------------------------ */
#pragma omp parallel for schedule(dynamic, 1)
    for (int64_t i = 0; i < static_cast<int64_t>(N); ++i) {
        size_t ui = static_cast<size_t>(i) * N;
        /* fill U[i][j] for j >= i */
        for (size_t j = i; j < N; ++j) {
            double sum = A_dense[ui + j];
            for (size_t k = 0; k < i; ++k)
                sum -= L[ui + k] * U[k * N + j];
            U[ui + j] = sum;
        }
        /* fill L[i][j] for j < i */
        for (size_t j = 0; j < i; ++j) {
            double sum = A_dense[ui + j];
            for (size_t k = 0; k < j; ++k)
                sum -= L[ui + k] * U[k * N + j];
            L[ui + j] = sum / U[j * N + j];
        }
        /* diagonal of L is 1 */
        L[ui + i] = 1.0;
    }
}
