/*
 * Compute one iteration of a 3‑point 1‑D Jacobi stencil.
 *
 *   output[i] = (input[i-1] + input[i] + input[i+1]) / 3
 *
 * Out‑of‑bounds accesses return 0. The function preserves the exact
 * semantics of the original code while employing simple range based
 * OpenMP parallelisation for maximal throughput on a modern x86‑64
 * host with 8 hardware threads.
 */

inline constexpr double INV3 = 1.0 / 3.0;

void jacobi1D(std::vector<double> const& input,
              std::vector<double> &output)
{
    const size_t N = input.size();
    if (N == 0) return;

    /* First element – left neighbour missing */
#pragma omp parallel for schedule(static)
    for (size_t i = 0; i < 1; ++i) {
        output[i] = (input[i] + input[i + 1]) * INV3;
    }

    /* Middle elements – all neighbours present */
#pragma omp parallel for schedule(static)
    for (size_t i = 1; i + 1 < N; ++i) {
        output[i] = (input[i - 1] + input[i] + input[i + 1]) * INV3;
    }

    /* Last element – right neighbour missing */
#pragma omp parallel for schedule(static)
    for (size_t i = N - 1; i < N; ++i) {
        output[i] = (input[i] + input[i - 1]) * INV3;
    }
}
