   output: 5.5
*/
inline double area2(const Point& a, const Point& b, const Point& c) noexcept {
    // 2 * area (always non‑negative)
    return std::abs(a.x * (b.y - c.y) + b.x * (c.y - a.y) + c.x * (a.y - b.y));
}

double smallestArea(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    const Point* p = points.data();
    double best = std::numeric_limits<double>::max();

    #pragma omp parallel for schedule(dynamic,1024) reduction(min : best)
    for (std::size_t i = 0; i < n - 2; ++i) {
        const Point& pa = p[i];
        for (std::size_t j = i + 1; j < n - 1; ++j) {
            const Point& pb = p[j];
            for (std::size_t k = j + 1; k < n; ++k) {
                const double a2 = area2(pa, pb, p[k]);
                if (a2 < best) best = a2;
            }
        }
    }

    return 0.5 * best;   // convert back to actual area
}
