#pragma once
#include <vector>
#include <cmath>
#include <algorithm>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Solve the sparse linear system Ax=b for x.
   A is a sparse NxN matrix in COO format. x and b are dense vectors with N elements.
   Example:
   input: A=[{0,0,1}, {0,1,1}, {1,1,-2}] b=[1,4]
   output: x=[3,-2]
*/
inline void solveLinearSystem(std::vector<COOElement> const& A,
                               std::vector<double> const& b,
                               std::vector<double>& x,
                               size_t N)
{
    /* Allocate a single contiguous dense matrix and a copy of b */
    std::vector<double> matrix(N * N, 0.0);
    std::vector<double> b_copy(b.begin(), b.end());

    /* Fill the dense matrix from COO */
    for (auto const& e : A)
        matrix[e.row * N + e.column] = e.value;

    x.assign(N, 0.0);

    /* ----- Gaussian elimination with partial pivoting ----- */
    for (size_t i = 0; i < N; ++i) {
        /* Find pivot row */
        double maxVal = std::abs(matrix[i * N + i]);
        size_t maxRow = i;
        for (size_t k = i + 1; k < N; ++k) {
            double val = std::abs(matrix[k * N + i]);
            if (val > maxVal) {
                maxVal = val;
                maxRow = k;
            }
        }

        /* Swap rows i and maxRow in the matrix and in b_copy */
        if (maxRow != i) {
            for (size_t col = 0; col < N; ++col) {
                std::swap(matrix[maxRow * N + col], matrix[i * N + col]);
            }
            std::swap(b_copy[maxRow], b_copy[i]);
        }

        /* Eliminate rows below the pivot */
        double pivot = matrix[i * N + i];
        #pragma omp parallel for schedule(static)
        for (size_t k = i + 1; k < N; ++k) {
            double factor = -matrix[k * N + i] / pivot;
            size_t base_k = k * N;
            size_t base_i = i * N;
            matrix[k * N + i] = 0.0;         // explicit zeroing
            for (size_t j = i + 1; j < N; ++j) {
                matrix[base_k + j] += factor * matrix[base_i + j];
            }
            b_copy[k] += factor * b_copy[i];
        }
    }

    /* ----- Back substitution ----- */
    for (int i = static_cast<int>(N) - 1; i >= 0; --i) {
        double sum = b_copy[i];
        int base_i = i * N;
        #pragma omp parallel for reduction(-:sum) schedule(static)
        for (int k = i + 1; k < static_cast<int>(N); ++k) {
            sum -= matrix[base_i + k] * x[k];
        }
        x[i] = sum / matrix[base_i + i];
    }
}
