//  Find the k‑th smallest element in a vector of int
//  Returns the exact same value as a full sort would produce,
//  but uses std::nth_element for O(n) average time.
//
//  The function is thread‑safe and works with any valid k
//  (1‑based index, 1 ≤ k ≤ x.size()).  It intentionally
//  makes a local copy of the input to preserve the original
//  vector, exactly like the original implementation.
//

#pragma once
#include <vector>
#include <algorithm>

inline int findKthSmallest(std::vector<int> const& x, int k) {
    // Validate arguments (behaviour identical to original,
    // which assumes k is valid; added checks cost nothing in release)
    if (k <= 0 || k > static_cast<int>(x.size()))
        throw std::out_of_range("k is out of range");

    // Copy so we don't modify the caller's data
    std::vector<int> tmp = x;

    // nth_element gives the element that would be at position k-1
    // in a sorted sequence, with all smaller elements before it.
    std::nth_element(tmp.begin(), tmp.begin() + k - 1, tmp.end());

    return tmp[k - 1];
}
