#pragma once
#include <vector>
#include <complex>
#include <cmath>
#include <cstdint>
#include <omp.h>

/*
 * Optimised iterative Cooley–Tukey FFT.
 * Input length must be a power of two.
 * Output: real parts in r, imaginary parts in i.
 *
 * The implementation:
 *   * Pre‑computes a bit‑reversed index table.
 *   * Uses a single vector for the working array (in place).
 *   * Parallelises the outer loops of every stage with OpenMP.
 *   * Avoids temporary allocations inside the inner loops.
 */
void fft(std::vector<std::complex<double>> const& x,
         std::vector<double> &r,
         std::vector<double> &i)
{
    const std::size_t N = x.size();
    std::vector<std::complex<double>> data = x;        // work buffer

    /* ----- pre‑compute bit‑reverse table ----- */
    std::size_t m = 0;
    for (std::size_t tmp = N; tmp > 1; tmp >>= 1) ++m;
    std::vector<std::size_t> rev(N);
    for (std::size_t n = 0; n < N; ++n) {
        std::size_t x = n, y = 0;
        for (std::size_t i = 0; i < m; ++i) {
            y = (y << 1) | (x & 1);
            x >>= 1;
        }
        rev[n] = y;
    }

    /* ----- bit‑reverse permutation ----- */
    for (std::size_t i = 0; i < N; ++i) {
        std::size_t j = rev[i];
        if (j > i) std::swap(data[i], data[j]);
    }

    /* ----- table of twiddle factors ----- */
    std::vector<std::complex<double>> twiddles(N / 2);
    const double pi  = std::acos(-1.0);
    for (std::size_t k = 0; k < N / 2; ++k) {
        double t = -2.0 * pi * k / static_cast<double>(N);
        twiddles[k] = std::complex<double>(std::cos(t), std::sin(t));
    }

    /* ----- iterative decimation‑in‑time ----- */
    for (std::size_t s = 1; s <= m; ++s) {
        std::size_t m_ = 1u << s;          // sub‑FFT size
        std::size_t half = m_ >> 1;         // butterfly width
        std::size_t step = N / m_;          // step between butterflies
        std::size_t tbl = N / m_;           // twiddle stride

        #pragma omp parallel for schedule(static)
        for (std::size_t k = 0; k < N; k += m_) {
            for (std::size_t j = 0; j < half; ++j) {
                std::size_t idx = k + j;
                std::size_t idx_op = idx + half;
                std::size_t tw = j * tbl;

                std::complex<double> t = data[idx_op] * twiddles[tw];
                data[idx_op] = data[idx] - t;
                data[idx] += t;
            }
        }
    }

    /* ----- store result ----- */
    r.resize(N);
    i.resize(N);
    for (std::size_t j = 0; j < N; ++j) {
        r[j] = data[j].real();
        i[j] = data[j].imag();
    }
}
