#pragma once
#include <vector>
#include <unordered_map>
#include <thread>
#include <omp.h>

struct COOElement {
    size_t row, column;
    double value;
};

/* Compute the matrix multiplication Y = A X.
   A : MxK sparse matrix in COO format.
   X : KxN sparse matrix in COO format.
   Y : MxN dense matrix in row‑major order.
   Behaviour is identical to the reference implementation. */
void spmm(const std::vector<COOElement>& A,
          const std::vector<COOElement>& X,
          std::vector<double>& Y,
          size_t M, size_t K, size_t N) {

    /* Initialise the result matrix. */
    Y.assign(M * N, 0.0);

    /* Build a hash table from rows of X to all elements in that row.
       This allows O(1) lookup when matching a column of A with a row of X. */
    std::unordered_multimap<size_t, COOElement> x_map;
    x_map.reserve(X.size() * 2);
    for (const auto& x : X)
        x_map.emplace(x.row, x);

    /* Create a local Y for each thread to avoid atomic operations. */
    const int num_threads = std::thread::hardware_concurrency();
    std::vector<std::vector<double>> y_local(num_threads, std::vector<double>(M * N, 0.0));

    #pragma omp parallel
    {
        const int tid = omp_get_thread_num();
        std::vector<double>& y = y_local[tid];

        #pragma omp for schedule(static)
        for (size_t i = 0; i < A.size(); ++i) {
            const auto& a = A[i];
            auto range = x_map.equal_range(a.column);
            for (auto it = range.first; it != range.second; ++it) {
                const auto& x = it->second;
                y[a.row * N + x.column] += a.value * x.value;
            }
        }
    }

    /* Merge all partial results into the final matrix. */
    for (const auto& y : y_local)
        for (size_t i = 0; i < M * N; ++i)
            Y[i] += y[i];
}
