#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

// A small helper table: for each (current, neighborCount) pair we encode the next state.
// 0 = dead, 1 = alive
static constexpr unsigned char transition[2][9] = {
    // if old cell is dead
    {0,0,0,1,0,0,0,0,0},   // neighbor counts 0..8
    // if old cell is alive
    {0,0,1,1,0,0,0,0,0}
};

// Main function
inline void gameOfLife(const std::vector<int> &input, std::vector<int> &output, size_t N)
{
    // Ensure input and output have sufficient size; the harness guarantees this.
    const size_t stride = N;            // help compiler
    const int *in = input.data();
    int *out = output.data();

    // OpenMP parallel for with collapse to use all 8 threads on the two loops.
    #pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i)
    {
        for (size_t j = 0; j < N; ++j)
        {
            // Compute sum of the 8 neighbours
            const size_t idx = i * stride + j;
            int sum = 0;
            if (i)           sum += in[(i-1)*stride + j];
            if (i+1 < N)     sum += in[(i+1)*stride + j];
            if (j)           sum += in[i*stride + j-1];
            if (j+1 < N)     sum += in[i*stride + j+1];
            if (i && j)          sum += in[(i-1)*stride + j-1];
            if (i && j+1 < N)    sum += in[(i-1)*stride + j+1];
            if (i+1 < N && j)    sum += in[(i+1)*stride + j-1];
            if (i+1 < N && j+1 < N) sum += in[(i+1)*stride + j+1];

            // Look up the next state
            out[idx] = static_cast<int>(transition[in[idx] & 1][sum]);
        }
    }
}
