#pragma once
#include <vector>
#include <cstddef>
#include <cstddef>
#include <omp.h>

/* Multiply the matrix A by the vector x. Store the results in the vector y.
   A is an MxN matrix stored in row-major, x has N elements, and y has M elements.
   Example:
   input: A=[[1, -1, 2], [0, -3, 1]] x=[2, 1, 0]
   output: y=[1, -3]
*/
inline void gemv(std::vector<double> const& A,
                 std::vector<double> const& x,
                 std::vector<double> &y,
                 std::size_t M, std::size_t N)
{
    // Ensure sizes are consistent
    if (A.size() < M * N || x.size() < N || y.size() < M) return;

    // Use pointer arithmetic for speed
    const double* Ap = A.data();
    const double* xp = x.data();
    double* yp = y.data();

    // Cache‑blocking parameters (tuned for typical L1/L2 sizes)
    constexpr std::size_t ROW_BLOCK = 64;   // rows per inner block
    constexpr std::size_t COL_BLOCK = 64;   // columns per inner block

    #pragma omp parallel for schedule(static)
    for (std::size_t i0 = 0; i0 < M; i0 += ROW_BLOCK) {
        std::size_t i_end = std::min(i0 + ROW_BLOCK, M);
        for (std::size_t j0 = 0; j0 < N; j0 += COL_BLOCK) {
            std::size_t j_end = std::min(j0 + COL_BLOCK, N);
            for (std::size_t i = i0; i < i_end; ++i) {
                double sum = 0.0;
                const double* arow = Ap + i * N + j0;
                const double* bcol = xp + j0;
                for (std::size_t j = j0; j < j_end; ++j, ++arow, ++bcol) {
                    sum += (*arow) * (*bcol);
                }
                // Accumulate partial results from previous blocks
                yp[i] += sum;
            }
        }
    }
}
