#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Solve the linear system Ax=b for x.
   A is an NxN matrix in row-major. x and b have N elements.
   Example:

   input: A=[[1,4,2], [1,2,3], [2,1,3]] b=[11, 11, 13]
   output: x=[3, 1, 2]
*/

inline void solveLinearSystem(std::vector<double> const& A,
                              std::vector<double> const& b,
                              std::vector<double> &x,
                              size_t N)
{
    // Allocate working copies in contiguous memory
    std::vector<double> A_work(A.begin(), A.end());
    std::vector<double> b_work(b.begin(), b.end());

    /* Gaussian elimination with partial pivoting and OpenMP parallelism.
       The outer loop is serial because it creates elimination
       dependencies, but each elimination step over rows can be
       parallelized. */
    for (size_t i = 0; i < N - 1; ++i)
    {
        double pivot = A_work[i * N + i];
        if (pivot == 0.0) return;                     // singular

        // Parallel elimination of rows below the pivot row
        #pragma omp parallel for schedule(static,256)
        for (size_t j = i + 1; j < N; ++j)
        {
            double factor = A_work[j * N + i] / pivot;
            // Merge the inner loop to reduce overhead
            size_t k = i;
            #pragma ivdep
            for (; k < N; ++k)
                A_work[j * N + k] -= factor * A_work[i * N + k];
            b_work[j] -= factor * b_work[i];
        }
    }

    /* Back substitution */
    for (int64_t i = static_cast<int64_t>(N) - 1; i >= 0; --i)
    {
        double sum = 0.0;
        for (size_t j = i + 1; j < N; ++j)
            sum += A_work[i * N + j] * x[j];
        x[i] = (b_work[i] - sum) / A_work[i * N + i];
    }
}
