#include <omp.h>

static constexpr int8_t edgeKernel[3][3] = {
    {-1, -1, -1},
    {-1,  8, -1},
    {-1, -1, -1}
};

// Convolve the edge kernel with a grayscale image.
//
// Parallelised with OpenMP.
inline void convolveKernel(const std::vector<int> &imageIn,
                           std::vector<int>       &imageOut,
                           const size_t N) noexcept
{
    const int *restrict src = imageIn.data();
          int *restrict dst = imageOut.data();

    // If image is too small we just copy the input.
    if (N <= 2u) {
        std::copy(src, src + N * N, dst);
        return;
    }

#pragma omp parallel for collapse(2) schedule(static)
    for (size_t i = 0; i < N; ++i) {
        for (size_t j = 0; j < N; ++j) {
            // we can avoid re‑computing the boundaries by using the
            // pre‑condition that the kernel is 3×3.
            int sum = 0;

            // access neighbours explicitly: (-1,-1) ... (+1,+1)
            // inline small loops for speed.
            //
            // The compiler will unroll these because they are constant.
            uint64_t offset = i * N + j;

            // top‑row
            if (i > 0) {
                if (j > 0)   sum += src[(i-1)*N + j-1] * edgeKernel[0][0];
                sum += src[(i-1)*N + j  ] * edgeKernel[0][1];
                if (j+1 < N) sum += src[(i-1)*N + j+1] * edgeKernel[0][2];
            }
            // middle row
            if (j > 0)   sum += src[ offset - 1 ] * edgeKernel[1][0];
            sum += src[ offset ] * edgeKernel[1][1];
            if (j+1 < N) sum += src[ offset + 1 ] * edgeKernel[1][2];
            // bottom row
            if (i+1 < N) {
                if (j > 0)   sum += src[(i+1)*N + j-1] * edgeKernel[2][0];
                sum += src[(i+1)*N + j  ] * edgeKernel[2][1];
                if (j+1 < N) sum += src[(i+1)*N + j+1] * edgeKernel[2][2];
            }

            // clip to [0,255]
            dst[offset] = static_cast<int>(std::min(std::max(sum, 0), 255));
        }
    }
}
