#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>

/* Multiply the matrix A by the matrix B. Store the results in the matrix C.
   A is an MxK matrix, B is a KxN matrix, and C is a MxN matrix. The matrices are stored in row-major.
   Example:
   input: A=[[1, -1, 2], [0, -2, 1]] B=[[4, 1], [-1, 0], [2, 2]]
   output: C=[[9, 5], [4, 2]]
   The function accumulates into C (+=) exactly as the reference implementation.
   It uses a cache-friendly blocked algorithm and parallelises the outermost loop
   with OpenMP.  The work distribution is static to reduce scheduling overhead.
   No changes to the calling convention or matrix layout are made. */
inline void gemm(std::vector<double> const &A,
                 std::vector<double> const &B,
                 std::vector<double>       &C,
                 size_t M, size_t K, size_t N)
{
    constexpr size_t BLOCK = 64;          // block size tuned for typical L1 cache
    #pragma omp parallel for schedule(static)
    for (size_t ii = 0; ii < M; ii += BLOCK) {
        size_t i_max = std::min(ii + BLOCK, M);
        for (size_t kk = 0; kk < K; kk += BLOCK) {
            size_t k_max = std::min(kk + BLOCK, K);
            for (size_t jj = 0; jj < N; jj += BLOCK) {
                size_t j_max = std::min(jj + BLOCK, N);
                for (size_t i = ii; i < i_max; ++i) {
                    size_t a_base = i * K;
                    size_t c_base = i * N;
                    for (size_t k = kk; k < k_max; ++k) {
                        double a_val = A[a_base + k];
                        size_t b_base = k * N;
                        for (size_t j = jj; j < j_max; ++j) {
                            C[c_base + j] += a_val * B[b_base + j];
                        }
                    }
                }
            }
        }
    }
}
