/* Sort the vector `x` of complex numbers by their magnitude in ascending order.
   The implementation uses `std::norm` (squared magnitude) in the comparator
   to avoid the costly `sqrt` performed by `std::abs`, and the standard
   `std::sort` algorithm. This preserves the exact behaviour of the original
   code while improving performance. */
inline void sortComplexByMagnitude(std::vector<std::complex<double>>& x)
{
    // Inlining comparator for speed
    std::sort(x.begin(), x.end(),
              [](const std::complex<double>& a, const std::complex<double>& b)
              {
                  // Compare squared magnitudes instead of actual magnitudes
                  return std::norm(a) < std::norm(b);
