```cpp
#pragma once
#include <vector>
#include <algorithm>
#include <cmath>
#include <cstddef>
#include <numeric>
#include <utility>

struct Point {
    double x, y;
};

static inline double cross(const Point& a, const Point& b, const Point& c) noexcept {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

static inline double dist(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return std::sqrt(dx * dx + dy * dy);
}

/* Return the perimeter of the smallest convex polygon that contains all the points in the vector points.
   Example:
   input: [{0, 3}, {1, 1}, {2, 2}, {4, 4}, {0, 0}, {1, 2}, {3, 1}, {3, 3}]
   output: 13.4477
*/
inline double convexHullPerimeter(const std::vector<Point>& points) {
    const std::size_t n = points.size();
    if (n < 3) return 0.0;

    // Copy and sort points
    std::vector<Point> sorted(points);
    std::sort(sorted.begin(), sorted.end(), [](const Point& a, const Point& b) {
        return (a.x < b.x) || (a.x == b.x && a.y < b.y);
    });

    std::vector<Point> hull(2 * n);
    std::size_t k = 0;

    // Lower hull
    for (std::size_t i = 0; i < n; ++i) {
        while (k >= 2 && cross(hull[k - 2], hull[k - 1], sorted[i]) <= 0) --k;
        hull[k++] = std::move(sorted[i]);
    }

    // Upper hull
    for (std::size_t i = n - 1, t = k + 1; i > 0; --i) {
        while (k >= t && cross(hull[k - 2], hull[k - 1], sorted[i - 1]) <= 0) --k;
        hull[k++] = std::move(sorted[i - 1]);
    }

    hull.resize(k - 1);   // last point == first point
    const std::size_t m = hull.size();

    double perimeter = 0.0;
#pragma omp parallel for reduction(+:perimeter)
    for (std::ptrdiff_t i = 0; i < static_cast<std::ptrdiff_t>(m); ++i) {
        const Point& p1 = hull[i];
        const Point& p2 = hull[(i + 1) % m];
        perimeter += dist(p1, p2);
    }

    return perimeter;
}
