/* Return true if `val` is only in one of vectors x or y.
   Return false if it is in both or neither.
   The logic is identical to the original but
   implementation uses raw pointers for maximal speed. */
inline bool xorContains(const std::vector<int> &x, const std::vector<int> &y, int val)
{
    const std::size_t nx = x.size();
    const std::size_t ny = y.size();

    const int* px = x.data();
    const int* py = y.data();

    bool foundInX = false;
    for (std::size_t i = 0; i < nx; ++i) {
        if (px[i] == val) {
            foundInX = true;
            break;
        }
    }

    if (foundInX) {
        // value found in x but must not be in y
        for (std::size_t i = 0; i < ny; ++i) {
            if (py[i] == val) {
                return false;          // found in both
            }
        }
        return true;                   // found only in x
    } else {
        // value not in x, so it must not be in y
        for (std::size_t i = 0; i < ny; ++i) {
            if (py[i] == val) {
                return false;          // found only in y
            }
        }
        return false;                  // found in neither
    }
}
