#pragma once
#include <algorithm>
#include <numeric>
#include <vector>

/*
 * Compute the rank (index in the sorted order) for each element of `x`.
 * The result is written into `ranks_`. The function has the same
 * semantics as the original implementation but is tuned for speed on
 * modern x64 hardware with OpenMP support.  `x` is not modified.
 *
 * Parameters
 * ----------
 *  x        : const reference to a vector of floats (input)
 *  ranks_   : reference to a vector of size_t (output).  It will be
 *           resized to `x.size()` if necessary.
 */
inline void ranks(std::vector<float> const& x, std::vector<size_t>& ranks_) {
    const size_t n = x.size();
    if (ranks_.size() != n) ranks_.resize(n);

    /* 1. Build a vector of indices 0 .. n-1  */
    std::vector<size_t> idx(n);
    std::iota(idx.begin(), idx.end(), 0);

    /* 2. Sort indices according to the corresponding values in x.  */
    /*    The lambda captures `x` by reference.  The comparison is
     *    inlined, so the sort is as fast as possible.                 */
    std::sort(idx.begin(), idx.end(),
              [&](size_t a, size_t b) noexcept { return x[a] < x[b]; });

    /* 3. Translate the sorted order back into ranks.  */
    /*    This loop is trivially parallelizable but the cost is
     *    dominated by the sort, so a single loop is fine.         */
    for (size_t i = 0; i < n; ++i) {
        ranks_[idx[i]] = i;
    }
}
