#include <cmath>
#include <cstdint>
#include <immintrin.h>
#include <omp.h>

#if !defined(M_PI)
#define M_PI 3.14159265358979323846
#endif

// -----------------------------------------------------------------------------
// In‑lined helper for complex multiplication without branching
static inline std::complex<double> mul(const std::complex<double>& a,
                                       const std::complex<double>& b)
{
    return std::complex<double>(a.real()*b.real() - a.imag()*b.imag(),
                                a.real()*b.imag() + a.imag()*b.real());
}

// -----------------------------------------------------------------------------
// Bit‑reversal lookup table (32‑bit)
static uint32_t bit_reverse32(uint32_t x)
{
    x = ((x >> 1) & 0x55555555) | ((x & 0x55555555) << 1);
    x = ((x >> 2) & 0x33333333) | ((x & 0x33333333) << 2);
    x = ((x >> 4) & 0x0f0f0f0f) | ((x & 0x0f0f0f0f) << 4);
    x = ((x >> 8) & 0x00ff00ff) | ((x & 0x00ff00ff) << 8);
    x = ((x >> 16) & 0x0000ffff) | ((x & 0x0000ffff) << 16);
    return x;
}

// -----------------------------------------------------------------------------
// Main FFT routine – in‑place, radix‑2 iterative Cooley‑Tukey
void fft(std::vector<std::complex<double>> const& x,
         std::vector<std::complex<double>>& output)
{
    const std::size_t N = x.size();
    output = x;                       // work in place

    // Pre‑compute twiddle factors for each stage
    std::vector<std::complex<double>> twiddles(N / 2);
    const double root = -2.0 * M_PI / static_cast<double>(N);
    for (std::size_t i = 0; i < N / 2; ++i)
        twiddles[i] = std::polar(1.0, root * static_cast<double>(i));

    // Iterative FFT
    for (std::size_t stage = 1, m = 2; m <= N; stage++, m <<= 1)
    {
        const std::size_t half = m >> 1;
        const std::size_t step = N >> stage;

        // Parallelise the outer inner‑loop (each butterfly scope is independent)
        #pragma omp parallel for schedule(static)
        for (std::size_t j = 0; j < half; ++j)
        {
            const std::complex<double> w = twiddles[j * step];
            for (std::size_t k = j; k < N; k += m)
            {
                std::size_t t = k + half;
                std::complex<double> temp = output[t];
                output[t] = output[k] - temp * w;
                output[k] += temp * w;
            }
        }
    }

    // Bit‑reversal permutation (single pass – no parallelisation needed)
    const std::size_t logN = static_cast<std::size_t>(std::log2(static_cast<double>(N)));
    for (std::size_t i = 0; i < N; ++i)
    {
        std::size_t j = bit_reverse32(static_cast<uint32_t>(i)) >> (32 - logN);
        if (j > i)
        {
            std::swap(output[i], output[j]);
        }
    }
}
