struct Point {
    double x, y;
};

inline double cross(const Point& a, const Point& b, const Point& c) {
    return (b.x - a.x) * (c.y - a.y) - (b.y - a.y) * (c.x - a.x);
}

/* Compute the convex hull of a set of points using the
 * monotone chain algorithm (O(n log n)). The function
 * preserves the original behaviour but is tuned for
 * speed on a modern x86‑64 system with up to 8 threads.
 */
void convexHull(const std::vector<Point>& points, std::vector<Point>& hull) {
    const std::size_t n = points.size();
    if (n < 3) {
        hull = points;
        return;
    }

    /* 1) Sort by x, then y.  If OpenMP is available we use the
     *    GCC parallel sort; otherwise std::sort is used.
     */
    std::vector<Point> sorted = points;
#ifdef _OPENMP
    std::sort(std::execution::par, sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });
#else
    std::sort(sorted.begin(), sorted.end(),
              [](const Point& a, const Point& b) {
                  return a.x < b.x || (a.x == b.x && a.y < b.y);
              });
#endif

    /* 2) Build lower and upper hulls */
    std::vector<Point> hull_tmp;
    hull_tmp.reserve(2 * n);

    // lower hull
    for (const auto& p : sorted) {
        while (hull_tmp.size() >= 2 &&
               cross(hull_tmp[hull_tmp.size() - 2], hull_tmp.back(), p) <= 0) {
            hull_tmp.pop_back();
        }
        hull_tmp.push_back(p);
    }

    // upper hull
    const std::size_t lower_size = hull_tmp.size();
    for (std::size_t i = n - 1; i > 0; --i) {
        const Point& p = sorted[i - 1];
        while (hull_tmp.size() >= lower_size + 1 &&
               cross(hull_tmp[hull_tmp.size() - 2], hull_tmp.back(), p) <= 0) {
            hull_tmp.pop_back();
        }
        hull_tmp.push_back(p);
    }

    // The last point is omitted because it is the same as the
    // first point of the lower hull.
    hull_tmp.pop_back();

    /* 3) Move result into the output vector */
    hull = std::move(hull_tmp);
}
