// Inline helpers for speed
inline double fast_cos(double x) { return std::cos(x); }
inline double fast_sin(double x) { return std::sin(x); }

// Precomputed bit reversal table (for 32-bit indices)
// The table is generated once per call (size is power of two)
static std::vector<uint32_t> make_rev_table(uint32_t n)
{
    uint32_t m = 0;
    for (uint32_t tmp = n; tmp > 1; tmp >>= 1) ++m;          // log2(n)
    std::vector<uint32_t> rev(n);
    for (uint32_t i = 0; i < n; ++i)
    {
        uint32_t v = i;
        v = ((v & 0xaaaaaaaau) >> 1) | ((v & 0x55555555u) << 1);
        v = ((v & 0xccccccccu) >> 2) | ((v & 0x33333333u) << 2);
        v = ((v & 0xf0f0f0f0u) >> 4) | ((v & 0x0f0f0f0fu) << 4);
        v = ((v & 0xff00ff00u) >> 8) | ((v & 0x00ff00ffu) << 8);
        v = ((v >> 16) | (v << 16)) >> (32 - m);
        rev[i] = v;
    }
    return rev;
}

inline void bit_reverse(std::vector<std::complex<double>>& x)
{
    const uint32_t N = static_cast<uint32_t>(x.size());
    auto rev = make_rev_table(N);

    #pragma omp parallel for schedule(static)
    for (uint32_t i = 0; i < N; ++i)
    {
        uint32_t j = rev[i];
        if (j > i)
        {
            std::swap(x[i], x[j]);
        }
    }
}

inline void fft_helper(std::vector<std::complex<double>>& x)
{
    const uint32_t N = static_cast<uint32_t>(x.size());
    uint32_t m = 0;
    for (uint32_t tmp = N; tmp > 1; tmp >>= 1) ++m;          // log2(N)

    // Precompute twiddle base (exp(-i*2π/N))
    double theta = -2 * M_PI / static_cast<double>(N);
    std::complex<double> w_m(std::cos(theta), std::sin(theta));

    for (uint32_t s = 1; s <= m; ++s)
    {
        uint32_t m2 = 1u << s;           // size of sub-DFT
        uint32_t m1 = m2 >> 1;           // half size
        std::complex<double> w(1.0, 0.0);

        for (uint32_t j = 0; j < m1; ++j)
        {
            #pragma omp parallel for schedule(static)
            for (uint32_t k = j; k < N; k += m2)
            {
                uint32_t l = k + m1;
                std::complex<double> t = x[l] * w;
                x[l] = x[k] - t;
                x[k] += t;
            }
            w *= w_m;
        }
        // Update twiddle step for next stage
        w_m *= w_m;
    }

    bit_reverse(x);
}

inline void ifft(std::vector<std::complex<double>>& x)
{
    // Conjugate, forward FFT, conjugate again, scale
    const size_t N = x.size();
    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]);

    fft_helper(x);

    #pragma omp parallel for schedule(static)
    for (size_t i = 0; i < N; ++i)
        x[i] = std::conj(x[i]) / static_cast<double>(N);
}
