#pragma once
#include <vector>
#include <cstddef>
#include <omp.h>
#include <immintrin.h>   // AVX intrinsics

// Blocked, vectorised LU factorisation.
// Original algorithm is preserved by operating directly on the
// input matrix `A` stored in row‑major order.
/*
 *  In-place LU decomposition without pivoting:
 *
 *  A <- L * U   (L has 1s on its diagonal, U upper triangular).
 *
 *  The function works for any square matrix size `N`.
 */
inline void luFactorize(std::vector<double>& A, std::size_t N)
{
    constexpr std::size_t BLOCK = 64;                // block size – tuned for 8‑way SIMD + cache
    constexpr std::size_t ALIGN = 16;                // align step for AVX (16 doubles == 128 bytes)

    for (std::size_t k = 0; k < N; ++k)
    {
        //--- Factor row k (no divide‑by‑zero check – behaviour matches the original)
        const double pivot = A[k * N + k];
        double* row_k = &A[k * N];

        // Broadcast pivot & divise for later use
        __m256d pivot_vec = _mm256_set1_pd(pivot);

        // Divide elements to the right of the pivot
        std::size_t j = k + 1;
        for (; j + 3 < N; j += 4) {
            __m256d vec = _mm256_loadu_pd(&row_k[j]);          // load 4 elements
            vec = _mm256_div_pd(vec, pivot_vec);               // divide by pivot
            _mm256_storeu_pd(&row_k[j], vec);                  // store back
        }
        // Handle remainder of the row
        for (; j < N; ++j) row_k[j] /= pivot;

        //--- Update the trailing sub‑matrix
        const std::size_t remaining = N - (k + 1);
        if (remaining == 0) continue;

        // Parallelise over rows using OpenMP
        #pragma omp parallel for schedule(static, BLOCK)
        for (std::size_t i = k + 1; i < N; ++i)
        {
            const double factor = A[i * N + k];
            A[i * N + k] = factor;                    // store multiplier

            double* row_i = &A[i * N];
            double* row_k = &A[k * N];

            // Vectorised inner loop over columns
            std::size_t col = k + 1;
            // --- Process 4 doubles at a time
            for (; col + 3 < N; col += 4)
            {
                __m256d rhs  = _mm256_loadu_pd(&row_k[col]);          // U_kj
                __m256d mul   = _mm256_set1_pd(factor);               // factor
                __m256d prod  = _mm256_mul_pd(mul, rhs);              // factor * U_kj
                __m256d lhs   = _mm256_loadu_pd(&row_i[col]);          // L_ij
                __m256d res   = _mm256_sub_pd(lhs, prod);             // update
                _mm256_storeu_pd(&row_i[col], res);
            }
            // Handle remainder of columns
            for (; col < N; ++col) {
                row_i[col] -= factor * row_k[col];
            }
        }
    }
}
