#pragma once
#include <vector>
#include <algorithm>
#include <thread>
#include <mutex>
#include <future>

struct Result {
   int startTime, duration;
   float value;
};

//------------------------------------------------------------------------
// Parallel, thread‑friendly sort by startTime.
//
// The implementation splits the range into N segments (N = number of
// hardware threads or the smallest power‑of‑two greater than 1), sorts
// each segment in parallel, and finally merges the partially sorted
// ranges using a standard in‑place k‑way merge.  This keeps the exact
// ordering semantics of std::sort while exploiting the available cores.
//
// The implementation is intentionally lightweight: it avoids heavy
// template metaprogramming, uses only the C++ standard library,
// and retains a single function signature for the harness.
//
//-----------------------------------------------------------------------

inline void sortByStartTime(std::vector<Result> &results)
{
    if (results.size() < 2) return;

    // Determine the number of segments: bounded by hardware concurrency and size.
    const unsigned int hw_threads = std::thread::hardware_concurrency() ? std::thread::hardware_concurrency() : 2;
    const unsigned int min_segment = 1'024;            // avoid tiny segments
    const unsigned int segs = std::min<unsigned int>(
        hw_threads,
        static_cast<unsigned int>((results.size() + min_segment - 1) / min_segment));

    const size_t chunk = (results.size() + segs - 1) / segs;

    //--- 1. Parallel sort each chunk ------------------------------------
    std::vector<std::future<void>> futures;
    futures.reserve(segs);

    for (unsigned int i = 0; i < segs; ++i) {
        const size_t begin = i * chunk;
        const size_t end   = std::min(begin + chunk, results.size());
        futures.emplace_back(std::async(std::launch::async, [&, begin, end] {
            std::stable_sort(results.begin() + begin, results.begin() + end,
                             [](const Result &a, const Result &b) {
                                 return a.startTime < b.startTime;
                             });
        }));
    }

    for (auto &f : futures) f.get();  // wait for all sorts

    //--- 2. Merge the partially sorted chunks ----------------------------
    // Iterative binary merge: merge pairs, then pairs of pairs, …
    for (size_t merge_size = chunk; merge_size < results.size(); merge_size *= 2) {
        for (size_t start = 0; start + merge_size < results.size(); start += 2 * merge_size) {
            size_t mid   = std::min(start + merge_size, results.size());
            size_t end   = std::min(start + 2 * merge_size, results.size());
            std::inplace_merge(results.begin() + start,
                               results.begin() + mid,
                               results.begin() + end,
                               [](const Result &a, const Result &b) {
                                   return a.startTime < b.startTime;
                               });
        }
    }
}

