// Utility to compute squared distance
inline double sqrDist(const Point& a, const Point& b) noexcept {
    double dx = a.x - b.x;
    double dy = a.y - b.y;
    return dx * dx + dy * dy;
}

// Merge helper for strip processing
inline void mergeByY(std::vector<Point>& a, std::vector<Point>& tmp, size_t left, size_t right) {
    size_t i = left, j = left + (right - left) / 2, k = left, mid = i + (right - left) / 2;
    std::copy(a.begin() + left, a.begin() + mid, std::back_inserter(tmp));
    std::copy(a.begin() + mid, a.begin() + right, std::back_inserter(tmp));
    std::sort(tmp.begin(), tmp.end(), [](const Point& p1, const Point& p2){ return p1.y < p2.y; });

    tmp.clear();
}

// Recursive closest pair
double closestPairRec(std::vector<Point>& px, std::vector<Point>& py, size_t left, size_t right) {
    size_t n = right - left;
    if (n <= 3) {
        double minSq = std::numeric_limits<double>::max();
        for (size_t i = left; i < right; ++i)
            for (size_t j = i + 1; j < right; ++j)
                minSq = std::min(minSq, sqrDist(px[i], px[j]));
        std::inplace_merge(px.begin() + left, px.begin() + left + n / 2, px.begin() + right,
                           [](const Point& a, const Point& b){ return a.y < b.y; });
        return minSq;
    }

    size_t mid = left + n / 2;
    double midX = px[mid].x;

    double leftMin, rightMin;

#pragma omp task shared(px, py)
    leftMin = closestPairRec(px, py, left, mid);
#pragma omp task shared(px, py)
    rightMin = closestPairRec(px, py, mid, right);
#pragma omp taskwait

    double d = std::min(leftMin, rightMin);

    // Build strip: points within sqrt(d) of mid line
    std::vector<Point> strip;
    strip.reserve(n);
    for (size_t i = left; i < right; ++i)
        if (std::abs(px[i].x - midX) < std::sqrt(d))
            strip.push_back(px[i]);

    // Sort strip by y (already sorted by px but we need fresh order)
    std::sort(strip.begin(), strip.end(), [](const Point& a, const Point& b){ return a.y < b.y; });

    // Check strip
    for (size_t i = 0; i < strip.size(); ++i)
        for (size_t j = i + 1; j < strip.size() && (strip[j].y - strip[i].y) < std::sqrt(d); ++j)
            d = std::min(d, sqrDist(strip[i], strip[j]));

    // Merge by y for parent calls
    std::inplace_merge(px.begin() + left, px.begin() + mid, px.begin() + right,
                       [](const Point& a, const Point& b){ return a.y < b.y; });

    return d;
}

double closestPair(std::vector<Point> const& points) {
    size_t n = points.size();
    if (n < 2) return 0.0;

    std::vector<Point> px = points;
    std::sort(px.begin(), px.end(),
              [](const Point& a, const Point& b){ return a.x < b.x; });

    std::vector<Point> py = points;
    std::sort(py.begin(), py.end(),
              [](const Point& a, const Point& b){ return a.y < b.y; });

    double minSq;
#pragma omp parallel
    {
#pragma omp single nowait
        minSq = closestPairRec(px, py, 0, n);
    }
    return std::sqrt(minSq);
}
