#pragma once
#include <vector>
#include <cstddef>
#include <immintrin.h>   // AVX2 intrinsics

/* Return the index of the first even number in the vector x.
   Examples:
   input: [7, 3, 9, 5, 5, 7, 2, 9, 12, 11]
   output: 6
   input: [3, 8, 9, 9, 3, 4, 8, 6]
   output: 1
*/
size_t findFirstEven(const std::vector<int>& x) {
    const size_t n = x.size();
    if (n == 0) return 0;

    const int*  data = x.data();
    const int  * end  = data + n;
    const int  * p    = data;

    /* Process blocks of 8 ints using AVX2.
       An even number satisfies (value & 1) == 0.
       We compute a mask of odd/even bits and scan for the first even. */
    const __m256i mask = _mm256_set1_epi32(1);

    // Handle the head part until we reach an 8‑byte boundary
    for (; p < end && ((uintptr_t)p & 0x7) != 0; ++p) {
        if ((*p & 1) == 0) return p - data;
    }

    const int * const tail = end - (end - p) % 8;

    // Vectorised scan
    for (; p + 8 <= tail; p += 8) {
        __m256i vec = _mm256_loadu_si256(reinterpret_cast<const __m256i*>(p));
        // odd bits: 1 means odd, 0 means even
        __m256i odd = _mm256_and_si256(vec, mask);
        // Create a mask where 0 means even
        __m256i even_mask = _mm256_cmpeq_epi32(odd, _mm256_setzero_si256());
        // Convert to 32‑bit values 0/1
        __m256i cmp = _mm256_movemask_epi8(even_mask);
        // Each 8‑bit lane corresponds to an element; we only need the first 8 bits
        if (cmp) {
            // Find the first set bit
            unsigned idx8 = __builtin_ctz(cmp) / 2;  // each element occupies two bits in movemask
            return (p - data) + idx8;
        }
    }

    // Tail: remaining elements (< 8)
    for (; p < end; ++p) {
        if ((*p & 1) == 0) return p - data;
    }

    return n;
}
