#include <cstddef>
#include <omp.h>

/* Set every cell's value to 1 if it has exactly one neighbor that's a 1.
   Otherwise set it to 0.  Input and output are supplied as NxN grids
   stored in row‑major order.  The routine is fully parallelized with
   OpenMP and uses loop unrolling to reduce branch overhead.  The
   algorithmic behaviour is identical to the reference implementation. */
inline void cellsXOR(std::vector<int> const& input,
                     std::vector<int> &output,
                     std::size_t N)
{
    const std::size_t stride = N;
    const int *in  = input.data();
          int *out = output.data();

    // Parallelise across rows; each thread gets a contiguous chunk of rows.
    #pragma omp parallel for schedule(static)
    for (std::size_t i = 0; i < N; ++i) {
        const bool hasTop    = (i > 0);
        const bool hasBottom = (i < N-1);

        // For quick address calculation per row
        const std::size_t idxTop    = (i-1)*stride;
        const std::size_t idxBottom = (i+1)*stride;
        const std::size_t idxCurr   = i*stride;

        for (std::size_t j = 0; j + 7 < N; j += 8) {
            // Unroll a block of 8 columns.
            int c0 = (hasTop    && in[idxTop    + j    ] == 1) +
                    (hasBottom && in[idxBottom + j    ] == 1) +
                    (j > 0      && in[idxCurr   + j-1] == 1) +
                    (j + 1 < N  && in[idxCurr   + j+1] == 1);
            int c1 = (hasTop    && in[idxTop    + j+1] == 1) +
                    (hasBottom && in[idxBottom + j+1] == 1) +
                    (j+1 > 0    && in[idxCurr   + j  ] == 1) +
                    (j+2 < N    && in[idxCurr   + j+2] == 1);
            int c2 = (hasTop    && in[idxTop    + j+2] == 1) +
                    (hasBottom && in[idxBottom + j+2] == 1) +
                    (j+2 > 0    && in[idxCurr   + j+1] == 1) +
                    (j+3 < N    && in[idxCurr   + j+3] == 1);
            int c3 = (hasTop    && in[idxTop    + j+3] == 1) +
                    (hasBottom && in[idxBottom + j+3] == 1) +
                    (j+3 > 0    && in[idxCurr   + j+2] == 1) +
                    (j+4 < N    && in[idxCurr   + j+4] == 1);
            int c4 = (hasTop    && in[idxTop    + j+4] == 1) +
                    (hasBottom && in[idxBottom + j+4] == 1) +
                    (j+4 > 0    && in[idxCurr   + j+3] == 1) +
                    (j+5 < N    && in[idxCurr   + j+5] == 1);
            int c5 = (hasTop    && in[idxTop    + j+5] == 1) +
                    (hasBottom && in[idxBottom + j+5] == 1) +
                    (j+5 > 0    && in[idxCurr   + j+4] == 1) +
                    (j+6 < N    && in[idxCurr   + j+6] == 1);
            int c6 = (hasTop    && in[idxTop    + j+6] == 1) +
                    (hasBottom && in[idxBottom + j+6] == 1) +
                    (j+6 > 0    && in[idxCurr   + j+5] == 1) +
                    (j+7 < N    && in[idxCurr   + j+7] == 1);
            int c7 = (hasTop    && in[idxTop    + j+7] == 1) +
                    (hasBottom && in[idxBottom + j+7] == 1) +
                    (j+7 > 0    && in[idxCurr   + j+6] == 1) +
                    (j+8 < N    && in[idxCurr   + j+8] == 1);

            out[idxCurr + j]   = (c0 == 1) ? 1 : 0;
            out[idxCurr + j+1] = (c1 == 1) ? 1 : 0;
            out[idxCurr + j+2] = (c2 == 1) ? 1 : 0;
            out[idxCurr + j+3] = (c3 == 1) ? 1 : 0;
            out[idxCurr + j+4] = (c4 == 1) ? 1 : 0;
            out[idxCurr + j+5] = (c5 == 1) ? 1 : 0;
            out[idxCurr + j+6] = (c6 == 1) ? 1 : 0;
            out[idxCurr + j+7] = (c7 == 1) ? 1 : 0;
        }

        // Handle the remaining columns that were not a multiple of 8.
        for (std::size_t j = (N / 8) * 8; j < N; ++j) {
            int cnt = 0;
            if (hasTop    && in[idxTop    + j] == 1) ++cnt;
            if (hasBottom && in[idxBottom + j] == 1) ++cnt;
            if (j > 0     && in[idxCurr   + j-1] == 1) ++cnt;
            if (j + 1 < N && in[idxCurr   + j+1] == 1) ++cnt;
            out[idxCurr + j] = (cnt == 1) ? 1 : 0;
        }
    }
}
